#include "conv2d_relu_bias_add_custom_tiling.h"
#include "register/op_def_registry.h"

namespace {
static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }
}

// UB model per tile: yLocal (1x tileW) + xLocal (1x tileW) + small overhead => ~2 * tileW floats.
// We keep a conservative margin using 192KB per core and assume up to 5 * tileW floats as safe.
static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t BYTES_PER_FLOAT = 4;
static constexpr uint32_t SAFETY_FACTOR = 5;     // floats per element in worst case buffers
static constexpr uint32_t ALIGN_ELEMS    = 1024; // favor large DMA bursts
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dReluBiasAddCustomTilingData tiling;

    // Input shapes
    const gert::Shape *x_shape = context->GetInputShape(0);      // [N, Cin, H, W]
    const gert::Shape *w_shape = context->GetInputShape(1);      // [Cout, Cin, Kh, Kw]
    if (x_shape->GetOriginShape().GetDimNum() != 4 || w_shape->GetOriginShape().GetDimNum() != 4) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t H   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t W   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Cin_w= static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(1));
    const uint32_t Kh   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t Kw   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));
    if (Cin != Cin_w) return ge::GRAPH_FAILED;

    // Attributes
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *stride_h = attrs->GetAttrPointer<int32_t>(0);
    const int32_t *stride_w = attrs->GetAttrPointer<int32_t>(1);
    const int32_t *pad_h    = attrs->GetAttrPointer<int32_t>(2);
    const int32_t *pad_w    = attrs->GetAttrPointer<int32_t>(3);
    const int32_t *dil_h    = attrs->GetAttrPointer<int32_t>(4);
    const int32_t *dil_w    = attrs->GetAttrPointer<int32_t>(5);

    const uint32_t sH = static_cast<uint32_t>(*stride_h);
    const uint32_t sW = static_cast<uint32_t>(*stride_w);
    const uint32_t pH = static_cast<uint32_t>(*pad_h);
    const uint32_t pW = static_cast<uint32_t>(*pad_w);
    const uint32_t dH = static_cast<uint32_t>(*dil_h);
    const uint32_t dW = static_cast<uint32_t>(*dil_w);

    // Output dims
    const uint32_t Ho = (H + 2 * pH - dH * (Kh - 1u) - 1u) / sH + 1u;
    const uint32_t Wo = (W + 2 * pW - dW * (Kw - 1u) - 1u) / sW + 1u;

    // Optional conv_bias presence
    bool hasBias = context->GetInputShapeSize() > 2 && (context->GetInputShape(2)->GetOriginShape().GetShapeSize() > 0);

    // Tile width selection driven by UB budget
    uint32_t maxTile = UB_BUDGET_BYTES / (BYTES_PER_FLOAT * SAFETY_FACTOR);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileW = maxTile;
    if (Wo < tileW) {
        uint32_t aligned = AlignDown(Wo, ALIGN_ELEMS);
        tileW = (aligned > 0) ? aligned : Wo;
    }

    const uint32_t tilesPerRow = (tileW == 0) ? 1u : CeilDiv(Wo, tileW);
    const uint64_t totalTiles64 = static_cast<uint64_t>(N) * Cout * Ho * tilesPerRow;
    const uint32_t totalTiles = static_cast<uint32_t>(totalTiles64);

    // Choose blockDim
    uint32_t blockDim = totalTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_N(N);
    tiling.set_Cin(Cin);
    tiling.set_Cout(Cout);
    tiling.set_H(H);
    tiling.set_W(W);
    tiling.set_Kh(Kh);
    tiling.set_Kw(Kw);
    tiling.set_Ho(Ho);
    tiling.set_Wo(Wo);
    tiling.set_tileW(tileW);
    tiling.set_tilesPerRow(tilesPerRow);
    tiling.set_totalTiles(totalTiles);
    tiling.set_blockDim(blockDim);
    tiling.set_hasConvBias(hasBias ? 1u : 0u);
    tiling.set_strideH(sH);
    tiling.set_strideW(sW);
    tiling.set_padH(pH);
    tiling.set_padW(pW);
    tiling.set_dilH(dH);
    tiling.set_dilW(dW);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

