#include "pytorch_npu_helper.hpp"

static inline std::vector<int64_t> infer_conv2d_out_shape(const at::Tensor& x, const at::Tensor& w,
                                                          int64_t sH=1, int64_t sW=1,
                                                          int64_t pH=0, int64_t pW=0,
                                                          int64_t dH=1, int64_t dW=1) {
    auto N = x.size(0);
    auto Cin = x.size(1);
    auto H = x.size(2);
    auto W = x.size(3);
    (void)Cin;
    auto Cout = w.size(0);
    auto Kh = w.size(2);
    auto Kw = w.size(3);
    int64_t Ho = (H + 2 * pH - dH * (Kh - 1) - 1) / sH + 1;
    int64_t Wo = (W + 2 * pW - dW * (Kw - 1) - 1) / sW + 1;
    return {N, Cout, Ho, Wo};
}

at::Tensor conv2d_relu_bias_add_impl_npu(const at::Tensor& x,
                                         const at::Tensor& weight,
                                         c10::optional<at::Tensor> conv_bias_opt,
                                         const at::Tensor& post_bias) {
    auto out_sizes = infer_conv2d_out_shape(x, weight, 1, 1, 0, 0, 1, 1);
